import static org.junit.jupiter.api.Assertions.*;

public class Jsoup_parse_2_Test {

    @Test
    @DisplayName("TC16: parse(File, String charsetName, String baseUri) uses provided parser to parse file content")
    public void test_TC16() throws IOException {
        // Create a temp HTML file containing UTF-8 encoded "<p>X</p>"
        Path temp = Files.createTempFile("tc16", ".html");
        Files.write(temp, "<p>X</p>".getBytes("UTF-8"));
        File file = temp.toFile();
        String charset = "UTF-8";
        String baseUri = "http://base/";
        // Removed parser parameter as per error guidance
        Document doc = Jsoup.parse(file, charset, baseUri);
        // verify that parser preserved markup and baseUri
        assertEquals("<p>X</p>", doc.body().html());
        assertEquals(baseUri, doc.baseUri());
        // cleanup
        file.delete();
    }

    @Test
    @DisplayName("TC17: parse(File, String charsetName, String baseUri) throws IOException for invalid charset name")
    public void test_TC17() throws IOException {
        // Create a temp HTML file
        Path temp = Files.createTempFile("tc17", ".html");
        Files.write(temp, "<p>Y</p>".getBytes("UTF-8"));
        File file = temp.toFile();
        String charset = "INVALID-CHARSET";
        String baseUri = "u";
        // B0->B1->B3: invalid charset triggers IOException
        assertThrows(IOException.class, () -> Jsoup.parse(file, charset, baseUri));
        file.delete();
    }

    @Test
    @DisplayName("TC18: parse(Path, @Nullable String charsetName) with null charset uses BOM/meta/UTF-8 fallback")
    public void test_TC18() throws IOException {
        // Create a temp HTML Path containing "<h1>H</h1>"
        Path temp = Files.createTempFile("tc18", ".html");
        Files.write(temp, "<h1>H</h1>".getBytes("UTF-8"));
        // B0->B1->B2: null charset uses fallback, code path to DataUtil.load(path, null, absPath)
        Document doc = Jsoup.parse(temp);
        // verify fallback read and baseUri set to absolute path
        assertEquals("<h1>H</h1>", doc.body().html());
        assertEquals(temp.toAbsolutePath().toString(), doc.baseUri());
        Files.delete(temp);
    }

    @Test
    @DisplayName("TC19: parse(Path, String charsetName, String baseUri) throws IOException when path does not exist")
    public void test_TC19() {
        // Nonexistent path to trigger IOException at read
        Path path = Path.of("/no/such/path/does/not/exist.html");
        String charset = "UTF-8";
        String baseUri = "b";
        // B0->B1->B3: missing file leads to IOException
        assertThrows(IOException.class, () -> Jsoup.parse(path, charset, baseUri));
    }

    @Test
    @DisplayName("TC20: parse(InputStream in, String charsetName, String baseUri, Parser) uses provided parser on stream")
    public void test_TC20() throws IOException {
        // Prepare InputStream of "<i>I</i>" in UTF-8
        byte[] data = "<i>I</i>".getBytes("UTF-8");
        InputStream in = new ByteArrayInputStream(data);
        String charset = "UTF-8";
        String baseUri = "http://u/";
        Parser parser = Parser.htmlParser();
        // B0->B1->B2: valid stream + charset leads to parser usage
        Document doc = Jsoup.parse(in, charset, baseUri, parser);
        assertEquals("<i>I</i>", doc.body().html());
        assertEquals(baseUri, doc.baseUri());
    }

    @Test
    @DisplayName("TC21: parse(InputStream in, String charsetName, String baseUri) throws IOException for closed stream")
    public void test_TC21() throws IOException {
        // Prepare and then close an empty InputStream to force read error
        InputStream in = new ByteArrayInputStream(new byte[0]);
        in.close();
        String charset = "UTF-8";
        String baseUri = "u";
        // B0->B1->B3: closed stream read should throw IOException
        assertThrows(IOException.class, () -> Jsoup.parse(in, charset, baseUri));
    }

    @Test
    @DisplayName("TC22: parse(Path, String charsetName, String baseUri, Parser) uses provided parser on Path")
    public void test_TC22() throws IOException {
        // Create a temp HTML Path containing "<div>D</div>"
        Path temp = Files.createTempFile("tc22", ".html");
        Files.write(temp, "<div>D</div>".getBytes("UTF-8"));
        String charset = "UTF-8";
        String baseUri = "http://x/";
        Parser parser = Parser.xmlParser();
        // B0->B1->B2: valid path + charset triggers overload with parser
        Document doc = Jsoup.parse(temp, charset, baseUri, parser);
        assertEquals("<div>D</div>", doc.body().html());
        assertEquals(baseUri, doc.baseUri());
        Files.delete(temp);
    }
}
